%
% Generated by Neural Network Toolbox function genFunction, 26-Mar-2017 19:00:07.
% 
% [Y] = tmpNet(X,~,~) takes these arguments:
% 
%   X = 1xTS cell, 1 inputs over TS timesteps
%   Each X{1,ts} = 10xQ matrix, input #1 at timestep ts.
% 
% and returns:
%   Y = 1xTS cell of 1 outputs over TS timesteps.
%   Each Y{1,ts} = 2xQ matrix, output #1 at timestep ts.
% 
% where Q is number of samples (or series) and TS is the number of timesteps.

%#ok<*RPMT0>

% ===== NEURAL NETWORK CONSTANTS =====

% Input 1
x1_step1.keep = [1 2 3 5 6];
x1_step2.xoffset = [1;0.000219524059437097;3.14159265358979e-06;0.0823278402371568;0];
x1_step2.gain = [0.002002002002002;379.609112308767;26525.8238486492;0.0399388695497094;0.0432766655998397];
x1_step2.ymin = -1;

% Layer 1
b1 = [-0.84830242602696404;-4.667528455169518;0.81404534876945467;0.37514627971091774];
IW1_1 = [2.1123955582671701 -5.6452730095036996 -2.8599494108606707 0.21201697854181784 -0.80261694572059394;-0.035928644716376537 -2.3477410632648699 -0.94978310334468385 -2.6213111387380752 -1.1815338688718851;8.5129003562407117 1.9322852860199475 -0.026512903279860174 -4.6983108534372038 -6.1930404117634934;0.73676037541770234 2.1208245140826159 7.3335679106951375 -8.1177974943130824 0.12702967154371972];

% Layer 2
b2 = [-1.4263065012801122;-1.3975227085109796];
LW2_1 = [0.70944477946047346 -0.73425305002214691 0.32178923720346403 0.12610344492096565;0.92905505534705046 -0.9417175029563789 0.45457186296799623 0.1242585715101996];

% Output 1
y1_step1.ymin = -1;
y1_step1.gain = [0.514317465635919;10.3917334290447];
y1_step1.xoffset = [-0.000833831799524232;-0.00317895814720481];

% ===== SIMULATION ========

% Format Input Arguments
isCellX = iscell(X);
if ~isCellX, X = {X}; end;

% Dimensions
TS = size(X,2); % timesteps
if ~isempty(X)
  Q = size(X{1},2); % samples/series
else
  Q = 0;
end

% Allocate Outputs
Y = cell(1,TS);

% Time loop
for ts=1:TS

    % Input 1
    temp = removeconstantrows_apply(X{1,ts},x1_step1);
    Xp1 = mapminmax_apply(temp,x1_step2);
    
    % Layer 1
    a1 = tansig_apply(repmat(b1,1,Q) + IW1_1*Xp1);
    
    % Layer 2
    a2 = repmat(b2,1,Q) + LW2_1*a1;
    
    % Output 1
    Y{1,ts} = mapminmax_reverse(a2,y1_step1);
end

% Final Delay States
Xf = cell(1,0);
Af = cell(2,0);

% Format Output Arguments
if ~isCellX, Y = cell2mat(Y); end
end

% ===== MODULE FUNCTIONS ========

% Map Minimum and Maximum Input Processing Function
function y = mapminmax_apply(x,settings)
  y = bsxfun(@minus,x,settings.xoffset);
  y = bsxfun(@times,y,settings.gain);
  y = bsxfun(@plus,y,settings.ymin);
end

% Remove Constants Input Processing Function
function y = removeconstantrows_apply(x,settings)
  y = x(settings.keep,:);
end

% Sigmoid Symmetric Transfer Function
function a = tansig_apply(n,~)
  a = 2 ./ (1 + exp(-2*n)) - 1;
end

% Map Minimum and Maximum Output Reverse-Processing Function
function x = mapminmax_reverse(y,settings)
  x = bsxfun(@minus,y,settings.ymin);
  x = bsxfun(@rdivide,x,settings.gain);
  x = bsxfun(@plus,x,settings.xoffset);
end
